// ── FILTRO fromMe ──────────────────────
if ($json.body.data.key.fromMe === true) {
  return [];
}

// ── RATE LIMIT ────────────────────────
const numero = $json.body.data.key.remoteJid;
const ahora = Date.now();
const ventana = 60 * 60 * 1000;
const limite = 50;

const historialRaw = $getWorkflowStaticData('global');
if (!historialRaw.rateLimits) historialRaw.rateLimits = {};
const historial = historialRaw.rateLimits[numero] || [];
const recientes = historial.filter(t => ahora - t < ventana);

if (recientes.length >= limite) {
  return [];
}

recientes.push(ahora);
historialRaw.rateLimits[numero] = recientes;

// ── FECHA HOY Y MAÑANA (Bogotá) ────────
const ahoraBogota = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Bogota' }));
const dia = String(ahoraBogota.getDate()).padStart(2, '0');
const mes = String(ahoraBogota.getMonth() + 1).padStart(2, '0');
const anio = ahoraBogota.getFullYear();
const fechaHoy = `${dia}/${mes}/${anio}`;

const manana = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Bogota' }));
manana.setDate(manana.getDate() + 1);
const dman = String(manana.getDate()).padStart(2, '0');
const mman = String(manana.getMonth() + 1).padStart(2, '0');
const yman = manana.getFullYear();
const mañanaStr = `${dman}/${mman}/${yman}`;

// ── CALENDARIO PRÓXIMOS 7 DÍAS ─────────
const diasSemana = ['Domingo','Lunes','Martes','Miércoles','Jueves','Viernes','Sábado'];
let calendario = `Mañana: ${mañanaStr}\n`;
for (let i = 1; i <= 7; i++) {
  const d = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Bogota' }));
  d.setDate(d.getDate() + i);
  const dd = String(d.getDate()).padStart(2, '0');
  const mm = String(d.getMonth() + 1).padStart(2, '0');
  const yyyy = d.getFullYear();
  calendario += `${diasSemana[d.getDay()]}: ${dd}/${mm}/${yyyy}\n`;
}

// ── EXTRAER MENSAJE ────────────────────
const mensaje = $json.body.data.message?.conversation || 
                $json.body.data.message?.extendedTextMessage?.text || 
                '';

// ── VALIDACIÓN DE HORARIO ─────────────────────────────────────────────────
// Trabaja sobre la hora que el cliente menciona en el mensaje,
// no sobre la hora actual del servidor.
function detectarFueraDeHorario(texto) {
  const t = (texto || '').toLowerCase()
    .replace(/[áàä]/g,'a').replace(/[éèë]/g,'e')
    .replace(/[íìï]/g,'i').replace(/[óòö]/g,'o')
    .replace(/[úùü]/g,'u');

  // Detectar si la solicitud es para domingo (distinto horario)
  let esDomingo = /\bdomingo\b/.test(t);

  // Si el mensaje incluye una fecha DD/MM/YYYY, verificar si cae en domingo
  if (!esDomingo) {
    const mf = t.match(/\b(\d{1,2})\/(\d{1,2})\/(\d{4})\b/);
    if (mf) {
      const dFecha = new Date(parseInt(mf[3]), parseInt(mf[2]) - 1, parseInt(mf[1]));
      if (dFecha.getDay() === 0) esDomingo = true;
    }
  }

  const abreH   = esDomingo ? 10 : 9;
  const cierraH = esDomingo ? 17 : 19;

  let hora = null;

  // 1) HH:MM con am/pm opcional  →  "14:30", "2:30pm", "14:30 pm"
  const mHHMM = t.match(/\b(\d{1,2}):(\d{2})\s*([ap]\.?m\.?)?/);
  if (mHHMM) {
    let h = parseInt(mHHMM[1]);
    const m = parseInt(mHHMM[2]);
    const suf = (mHHMM[3] || '').replace(/\./g, '');
    if (suf.startsWith('p') && h < 12) h += 12;
    if (suf.startsWith('a') && h === 12) h = 0;
    hora = h + m / 60;
  }

  // 2) Número + "pm"  →  "3pm", "3 pm", "3 p.m."
  if (hora === null) {
    const mPm = t.match(/\b(\d{1,2})\s*p\.?m\.?\b/);
    if (mPm) { let h = parseInt(mPm[1]); if (h < 12) h += 12; hora = h; }
  }

  // 3) Número + "am"  →  "8am", "8 am", "8 a.m."
  if (hora === null) {
    const mAm = t.match(/\b(\d{1,2})\s*a\.?m\.?\b/);
    if (mAm) { let h = parseInt(mAm[1]); if (h === 12) h = 0; hora = h; }
  }

  // 4) "a las X de la tarde / noche"  →  pm
  if (hora === null) {
    const mT = t.match(/(?:a las|las)\s+(\d{1,2})(?:\s+de la|\s+en la)?\s+(?:tarde|noche)/);
    if (mT) { let h = parseInt(mT[1]); if (h < 12) h += 12; hora = h; }
  }

  // 5) "a las X de la mañana"  →  am
  if (hora === null) {
    const mM = t.match(/(?:a las|las)\s+(\d{1,2})(?:\s+de la)?\s+manana/);
    if (mM) { let h = parseInt(mM[1]); if (h === 12) h = 0; hora = h; }
  }

  // Sin hora detectada → no se puede validar
  if (hora === null) return { fueraDeHorario: false };

  // Dentro del horario → OK
  if (hora >= abreH && hora < cierraH) return { fueraDeHorario: false };

  const horarioTexto = esDomingo
    ? 'los domingos atendemos de 10:00 AM a 5:00 PM'
    : 'de lunes a sábado atendemos de 9:00 AM a 7:00 PM';

  return {
    fueraDeHorario: true,
    mensajeHorario: `Lo sentimos, esa hora está fuera de nuestro horario de atención. ` +
      `${horarioTexto[0].toUpperCase() + horarioTexto.slice(1)}. ¿Te puedo agendar en otro horario? 😊`
  };
}

const validacionHorario = detectarFueraDeHorario(mensaje);

if (mensaje.trim()) {
  return [{
    json: {
      textoOriginal: mensaje,
      numero: numero,
      timestamp: $json.body.data.messageTimestamp,
      procesado: true,
      fechaHoy: fechaHoy,
      calendario: calendario,
      fueraDeHorario: validacionHorario.fueraDeHorario,
      mensajeHorario: validacionHorario.mensajeHorario || null
    }
  }];
}

return [];

const output = $('AI Agent').item.json.output.split('|');
const servicio = output[1] || '';
const fecha = output[2] || '';
const hora = (output[3] || '').split('\n')[0].trim();
const nombre = $('Webhook').item.json.body.data.pushName || 'Cliente';
const numero = ($('Code in JavaScript').item.json.numero || '').replace('@s.whatsapp.net', '');
const numeroDueno = $env.OWNER_NUMBER;

// Construir datetimes para Google Calendar
const [dia, mes, anio] = fecha.split('/');
const fechaISO = `${anio}-${mes}-${dia}`;
const [hh, mm] = hora.split(':').map(Number);
const endHour = String(hh + 1).padStart(2, '0');
const startDateTime = `${fechaISO}T${hora}:00-05:00`;
const endDateTime = `${fechaISO}T${endHour}:${String(mm).padStart(2, '0')}:00-05:00`;

const textoDueno = `🔔 *Nueva cita agendada*\n\n👤 *Cliente:* ${nombre}\n📞 *Número:* ${numero}\n✂️ *Servicio:* ${servicio}\n📅 *Fecha:* ${fecha}\n⏰ *Hora:* ${hora}\n\n_Estado: Pendiente_ ✅`;
const textoCliente = `✅ ¡Tu cita quedó confirmada!\n\n✂️ *Servicio:* ${servicio}\n📅 *Fecha:* ${fecha}\n⏰ *Hora:* ${hora}\n\n¡Te esperamos en Peluquería Meyer! 💇‍♂️\nCualquier cambio, escríbenos aquí mismo 😊`;

return [{
  json: {
    numeroDueno,
    numeroCliente: numero,
    nombreCliente: nombre,
    servicio,
    fecha,
    hora,
    startDateTime,
    endDateTime,
    textoDueno,
    textoCliente,
    bodyDueno: JSON.stringify({ number: numeroDueno, text: textoDueno }),
    bodyCliente: JSON.stringify({ number: numero, text: textoCliente })
  }
}];

// Google Calendar - DESHABILITADO
// Credenciales migradas a variables de entorno
// Para reactivar: usar nodo nativo de Google Calendar de n8n
return $input.all();

const total = $input.first().json.total;
const numero = ($('Code in JavaScript').item.json.numero || '').replace(/@s\.whatsapp\.net/g, '').replace(/\D/g, '');
const partes = $('AI Agent').item.json.output.split('|');
return [{ json: { disponible: total == 0, fechaDeseada: partes[2]?.trim(), horaDeseada: partes[3]?.split('\n')[0].trim(), numero } }];

// Construir resumen de disponibilidad para los próximos 7 días
const slots = $input.all();
const diasSemana = ['Domingo','Lunes','Martes','Miércoles',
                    'Jueves','Viernes','Sábado'];
const meses = ['enero','febrero','marzo','abril','mayo','junio',
               'julio','agosto','septiembre','octubre','noviembre','diciembre'];

const porFecha = {};
for (const item of slots) {
  const fecha = item.json.fecha;
  const slot = item.json.slot;
  if (!porFecha[fecha]) porFecha[fecha] = [];
  porFecha[fecha].push(slot);
}

let disponibilidad = '';
for (const [fecha, horas] of Object.entries(porFecha)) {
  const d = new Date(fecha + 'T00:00:00');
  const nombreDia = diasSemana[d.getUTCDay()];
  const dia = d.getUTCDate();
  const mes = meses[d.getUTCMonth()];
  disponibilidad += `${nombreDia} ${dia} de ${mes}: ${horas.join(', ')}\n`;
}

// Pasar todo el contexto anterior más la disponibilidad
const prev = $('Code in JavaScript').item.json;
return [{
  json: {
    ...prev,
    disponibilidad: disponibilidad || 'Sin disponibilidad en los próximos 7 días'
  }
}];
